    off_t size = lseek(fd, 0, SEEK_END);
    lseek(fd, 0, SEEK_SET);
    // 创建 pipe
    int p[2];
    if (pipe(p) < 0) {
        perror("pipe");
        return 1;
    }
    // 使用 splice 将文件内容读入 pipe
    ssize_t n = splice(fd, NULL, p[1], NULL, size, 0);
