#define _GNU_SOURCE
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/mman.h>
#include <unistd.h>
#include <sys/stat.h>

int main(int argc, char **argv) {
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <target_file>\n", argv[0]);
        return 1;
    }
    const char *target = argv[1];
    int fd = open(target, O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 获取文件大小
    struct stat st;
    fstat(fd, &st);
    off_t file_size = st.st_size;

    // 创建pipe
    int p[2];
    if (pipe(p) == -1) {
        perror("pipe");
        return 1;
    }

    // 使用splice将文件内容映射到pipe读端
    loff_t offset = 0;
    ssize_t n = splice(fd, &offset, p[1], NULL, file_size, 0);
    if (n != file_size) {
        perror("splice");
        return 1;
